731: 			t.metrics.droppedSamplesTotal.WithLabelValues(reasonTooOld).Inc()
732: 			continue
733: 		}
734: 		t.seriesMtx.Lock()
735: 		lbls, ok := t.seriesLabels[s.Ref]
736: 		if !ok {
737: 			t.dataDropped.incr(1)
738: 			if _, ok := t.droppedSeries[s.Ref]; !ok {
739: 				t.logger.Info("Dropped sample for series that was not explicitly dropped via relabelling", "ref", s.Ref)
740: 				t.metrics.droppedSamplesTotal.WithLabelValues(reasonUnintentionalDroppedSeries).Inc()
741: 			} else {
742: 				t.metrics.droppedSamplesTotal.WithLabelValues(reasonDroppedSeries).Inc()
743: 			}
744: 			t.seriesMtx.Unlock()
745: 			continue
746: 		}
747: 		// TODO(cstyan): Handle or at least log an error if no metadata is found.
748: 		// See https://github.com/prometheus/prometheus/issues/14405
749: 		meta := t.seriesMetadata[s.Ref]
750: 		t.seriesMtx.Unlock()
751: 		// Start with a very small backoff. This should not be t.cfg.MinBackoff
752: 		// as it can happen without errors, and we want to pickup work after
753: 		// filling a queue/resharding as quickly as possible.
754: 		// TODO: Consider using the average duration of a request as the backoff.
755: 		backoff := model.Duration(5 * time.Millisecond)
756: 		for {
757: 			select {
758: 			case <-t.quit:
759: 				return false
760: 			default:
761: 			}
762: 			if t.shards.enqueue(s.Ref, timeSeries{
763: 				seriesLabels: lbls,
764: 				metadata:     meta,
